class Solution:
    def findSecondMinimumValue(self, root: Optional[TreeNode]) -> int:
        self.ans=10**9; self.root_val=root.val
        def dfs(n):
            if not n: return
            if n.val>self.root_val: self.ans=min(self.ans,n.val)
            else: dfs(n.left); dfs(n.right)
        dfs(root); return self.ans if self.ans<10**9 else -1

