class Solution {
    int ans=INT_MAX, rv;
    void dfs(TreeNode* n){
        if(!n) return;
        if(n->val>rv) ans=min(ans,n->val);
        else { dfs(n->left); dfs(n->right); }
    }
public:
    int findSecondMinimumValue(TreeNode* root){
        rv=root->val; dfs(root); return ans==INT_MAX?-1:ans;
    }
};
